function makeCounter() {
  let count = 0;
  return function() {
    return ++count;
  };
}
const counter = makeCounter();
console.log(counter()); // 1
console.log(counter()); // 2

const counter = (() => {
  let n = 0;
  return () => ++n;
})();
counter(); // 1
counter(); // 2
console.log(counter());

